import React from 'react';
import { Link } from 'react-router-dom';
import './Programs.css';

const Programs = () => {
  const programs = [
    { title: 'STRENGTH TRAINING', description: 'Build muscle and increase strength', icon: '💪' },
    { title: 'WEIGHT LOSS', description: 'Achieve your weight loss goals', icon: '🔥' },
    { title: 'PERSONAL TRAINING', description: 'One-on-one coaching', icon: '👥' },
    { title: 'CROSSFIT', description: 'High-intensity functional training', icon: '⚡' },
    { title: 'HIIT', description: 'Quick, intense workouts', icon: '⏱️' },
    { title: 'YOGA', description: 'Improve flexibility and balance', icon: '🧘' }
  ];

  return (
    <section className="programs-section">
      <div className="container">
        <h2 className="section-title">OUR PROGRAMS</h2>
        <p className="section-subtitle">Choose from a variety of programs</p>
        <div className="programs-grid">
          {programs.map((program, index) => (
            <div key={index} className="program-card">
              <div className="program-icon">{program.icon}</div>
              <h3>{program.title}</h3>
              <p>{program.description}</p>
              <Link to="/booking" className="program-btn">LEARN MORE</Link>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Programs;
